arguments.prompt:
You are implementing a logistics shipment tracking Blazor Web App. The project has already been scaffolded at `/tmp/sv-81f279d478fc4024995ae84637886663/ShipmentTracker/` with:
- `dotnet new blazor -int Auto -ai -au Individual`
- Two projects: `ShipmentTracker` (server) and `ShipmentTracker.Client` (WebAssembly)
- Global Interactive Auto mode — no need for `@rendermode` on individual pages
- ASP.NET Core Identity with SQLite already configured
- `ApplicationDbContext` in `ShipmentTracker/Data/ApplicationDbContext.cs`
- `ApplicationUser` in `ShipmentTracker/Data/ApplicationUser.cs`

## Requirements
1. Dispatchers view a list of shipments with status and destination
2. Customers check their shipment status and estimated delivery
3. Every page has interactive controls
4. Staff and customers authenticate with individual accounts

## Architecture (Auto mode rules)
- All interactive components MUST go in `.Client` project
- No direct DB access from `.Client` — use HTTP APIs
- Define service interfaces in `.Client`, implement with HttpClient there
- Server implements same interfaces with EF Core direct access
- Both Program.cs files register matching service implementations
- Expose data through minimal API endpoints in server Program.cs

## Implementation Plan

### 1. Shared Models — Create in `.Client` project (referenced by both)

Create `ShipmentTracker.Client/Models/Shipment.cs`:
```csharp
namespace ShipmentTracker.Client.Models;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public string? CustomerEmail { get; set; }
    public string? Description { get; set; }
    public double? WeightKg { get; set; }
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Cancelled
}
```

### 2. Service Interface — Create in `.Client` project

Create `ShipmentTracker.Client/Services/IShipmentService.cs`:
```csharp
namespace ShipmentTracker.Client.Services;

using ShipmentTracker.Client.Models;

public interface IShipmentService
{
    Task<List<Shipment>> GetAllShipmentsAsync();
    Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<Shipment> CreateShipmentAsync(Shipment shipment);
    Task<Shipment> UpdateShipmentAsync(Shipment shipment);
}
```

### 3. Client-side Implementation — HttpClient-based in `.Client` project

Create `ShipmentTracker.Client/Services/ClientShipmentService.cs`:
```csharp
using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ClientShipmentService(HttpClient httpClient) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await httpClient.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var response = await httpClient.GetAsync($"api/shipments/track/{trackingNumber}");
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<Shipment>();
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        var response = await httpClient.PostAsJsonAsync("api/shipments", shipment);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<Shipment>())!;
    }

    public async Task<Shipment> UpdateShipmentAsync(Shipment shipment)
    {
        var response = await httpClient.PutAsJsonAsync($"api/shipments/{shipment.Id}", shipment);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<Shipment>())!;
    }
}
```

### 4. Client Program.cs — Register services and HttpClient

Update `ShipmentTracker.Client/Program.cs` to add:
```csharp
using ShipmentTracker.Client.Services;

// ... existing code ...

builder.Services.AddScoped(sp => new HttpClient { BaseAddress = new Uri(builder.HostEnvironment.BaseAddress) });
builder.Services.AddScoped<IShipmentService, ClientShipmentService>();
```

### 5. Server-side Data — EF Core entity and DbContext

Update `ShipmentTracker/Data/ApplicationDbContext.cs` to add a `DbSet<ShipmentEntity>`:
```csharp
using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;

namespace ShipmentTracker.Data;

public class ApplicationDbContext(DbContextOptions<ApplicationDbContext> options) : IdentityDbContext<ApplicationUser>(options)
{
    public DbSet<ShipmentEntity> Shipments => Set<ShipmentEntity>();
}
```

Create `ShipmentTracker/Data/ShipmentEntity.cs`:
```csharp
using System.ComponentModel.DataAnnotations;

namespace ShipmentTracker.Data;

public class ShipmentEntity
{
    public int Id { get; set; }
    [MaxLength(20)]
    public string TrackingNumber { get; set; } = string.Empty;
    [MaxLength(200)]
    public string Origin { get; set; } = string.Empty;
    [MaxLength(200)]
    public string Destination { get; set; } = string.Empty;
    public int Status { get; set; }
    public DateTime CreatedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    [MaxLength(256)]
    public string? CustomerEmail { get; set; }
    [MaxLength(500)]
    public string? Description { get; set; }
    public double? WeightKg { get; set; }
}
```

### 6. Server-side Service Implementation

Create `ShipmentTracker/Services/ServerShipmentService.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ServerShipmentService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await db.Shipments.Select(e => MapToModel(e)).ToListAsync();
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var entity = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return entity is null ? null : MapToModel(entity);
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        var entity = MapToEntity(shipment);
        entity.TrackingNumber = GenerateTrackingNumber();
        entity.CreatedDate = DateTime.UtcNow;
        db.Shipments.Add(entity);
        await db.SaveChangesAsync();
        return MapToModel(entity);
    }

    public async Task<Shipment> UpdateShipmentAsync(Shipment shipment)
    {
        var entity = await db.Shipments.FindAsync(shipment.Id)
            ?? throw new InvalidOperationException("Shipment not found");
        entity.Origin = shipment.Origin;
        entity.Destination = shipment.Destination;
        entity.Status = (int)shipment.Status;
        entity.EstimatedDelivery = shipment.EstimatedDelivery;
        entity.CustomerEmail = shipment.CustomerEmail;
        entity.Description = shipment.Description;
        entity.WeightKg = shipment.WeightKg;
        await db.SaveChangesAsync();
        return MapToModel(entity);
    }

    private static Shipment MapToModel(ShipmentEntity e) => new()
    {
        Id = e.Id,
        TrackingNumber = e.TrackingNumber,
        Origin = e.Origin,
        Destination = e.Destination,
        Status = (ShipmentStatus)e.Status,
        CreatedDate = e.CreatedDate,
        EstimatedDelivery = e.EstimatedDelivery,
        CustomerEmail = e.CustomerEmail,
        Description = e.Description,
        WeightKg = e.WeightKg
    };

    private static ShipmentEntity MapToEntity(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = (int)s.Status,
        CreatedDate = s.CreatedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        CustomerEmail = s.CustomerEmail,
        Description = s.Description,
        WeightKg = s.WeightKg
    };

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(1000, 9999)}";
    }
}
```

