@code {
    [SupplyParameterFromQuery(Name = "number")]
    public string? InitialTrackingNumber { get; set; }

    private string trackingNumber = "";
    private string searchedNumber = "";
    private Shipment? shipment;
    private bool searched;
    private bool searching;

    protected override async Task OnInitializedAsync()
    {
        if (!string.IsNullOrWhiteSpace(InitialTrackingNumber))
        {
            trackingNumber = InitialTrackingNumber;
            await TrackAsync();
        }
    }

    private async Task TrackAsync()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;
        searching = true;
        searchedNumber = trackingNumber.Trim();
        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedNumber);
        searched = true;
        searching = false;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
