    }

    private async Task HandleSubmit()
    {
        if (shipment is null) return;
        submitting = true;
        successMessage = null;
        errorMessage = null;
        try
        {
            shipment = await ShipmentService.UpdateShipmentAsync(shipment);
            successMessage = "Shipment updated successfully.";
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to update: {ex.Message}";
        }
        finally
        {
            submitting = false;
        }
    }
}
