### 6. Server-side Service Implementation

Create `ShipmentTracker/Services/ServerShipmentService.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ServerShipmentService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await db.Shipments.Select(e => MapToModel(e)).ToListAsync();
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var entity = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return entity is null ? null : MapToModel(entity);
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        var entity = MapToEntity(shipment);
        entity.TrackingNumber = GenerateTrackingNumber();
        entity.CreatedDate = DateTime.UtcNow;
        db.Shipments.Add(entity);
        await db.SaveChangesAsync();
        return MapToModel(entity);
    }

    public async Task<Shipment> UpdateShipmentAsync(Shipment shipment)
    {
        var entity = await db.Shipments.FindAsync(shipment.Id)
            ?? throw new InvalidOperationException("Shipment not found");
        entity.Origin = shipment.Origin;
        entity.Destination = shipment.Destination;
        entity.Status = (int)shipment.Status;
        entity.EstimatedDelivery = shipment.EstimatedDelivery;
        entity.CustomerEmail = shipment.CustomerEmail;
        entity.Description = shipment.Description;
        entity.WeightKg = shipment.WeightKg;
        await db.SaveChangesAsync();
        return MapToModel(entity);
    }

    private static Shipment MapToModel(ShipmentEntity e) => new()
    {
        Id = e.Id,
        TrackingNumber = e.TrackingNumber,
        Origin = e.Origin,
        Destination = e.Destination,
        Status = (ShipmentStatus)e.Status,
        CreatedDate = e.CreatedDate,
        EstimatedDelivery = e.EstimatedDelivery,
        CustomerEmail = e.CustomerEmail,
        Description = e.Description,
        WeightKg = e.WeightKg
    };

    private static ShipmentEntity MapToEntity(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = (int)s.Status,
        CreatedDate = s.CreatedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        CustomerEmail = s.CustomerEmail,
        Description = s.Description,
        WeightKg = s.WeightKg
    };

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(1000, 9999)}";
    }
}
```

