```razor
@page "/shipments"
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Shipments</PageTitle>

<h1>Shipments</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="sortField">
            <option value="created">Sort by Date</option>
            <option value="destination">Sort by Destination</option>
            <option value="status">Sort by Status</option>
        </select>
    </div>
    <div class="col-md-2">
        <a class="btn btn-success w-100" href="shipments/new">+ New Shipment</a>
    </div>
</div>

@if (loading)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <div class="alert alert-info">No shipments found.</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Created</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in FilteredShipments)
                {
                    <tr>
                        <td><code>@shipment.TrackingNumber</code></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                        <td>@shipment.CreatedDate.ToString("MMM dd, yyyy")</td>
                        <td>@(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
                        <td>
                            <a class="btn btn-sm btn-outline-primary" href="@($"shipments/edit/{shipment.Id}")">Edit</a>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<Shipment> shipments = [];
    private bool loading = true;
    private string filterText = "";
    private string statusFilter = "";
    private string sortField = "created";

    private IEnumerable<Shipment> FilteredShipments
    {
        get
        {
            var query = shipments.AsEnumerable();

            if (!string.IsNullOrWhiteSpace(filterText))
                query = query.Where(s => s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)
                    || s.Origin.Contains(filterText, StringComparison.OrdinalIgnoreCase)
                    || s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase));

            if (!string.IsNullOrWhiteSpace(statusFilter) && Enum.TryParse<ShipmentStatus>(statusFilter, out var status))
                query = query.Where(s => s.Status == status);

            query = sortField switch
            {
                "destination" => query.OrderBy(s => s.Destination),
                "status" => query.OrderBy(s => s.Status),
                _ => query.OrderByDescending(s => s.CreatedDate)
            };

            return query;
        }
    }

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
        loading = false;
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-warning text-dark",
        ShipmentStatus.OutForDelivery => "bg-primary",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}
```

