@code {
    [SupplyParameterFromQuery(Name = "number")]
    public string? InitialTrackingNumber { get; set; }

    private string trackingNumber = "";
    private string searchedNumber = "";
    private Shipment? shipment;
    private bool searched;
    private bool searching;

    protected override async Task OnInitializedAsync()
    {
        if (!string.IsNullOrWhiteSpace(InitialTrackingNumber))
        {
            trackingNumber = InitialTrackingNumber;
            await TrackAsync();
        }
    }

    private async Task TrackAsync()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;
        searching = true;
        searchedNumber = trackingNumber.Trim();
        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedNumber);
        searched = true;
        searching = false;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackAsync();
    }

    private static string GetStatusDisplayText(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "Pending",
        ShipmentStatus.PickedUp => "Picked Up",
        ShipmentStatus.InTransit => "In Transit",
        ShipmentStatus.OutForDelivery => "Out for Delivery",
        ShipmentStatus.Delivered => "Delivered",
        ShipmentStatus.Cancelled => "Cancelled",
        _ => "Unknown"
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-warning text-dark",
        ShipmentStatus.OutForDelivery => "bg-primary",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Cancelled => "bg-danger",
        ShipmentStatus.Delivered => "bg-success",
        _ => "bg-primary progress-bar-striped progress-bar-animated"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Cancelled => 100,
        _ => 0
    };
}
